class Solution:
    def maxProfit(self, prices):
        n = len(prices)
        if n < 2:
            return 0
        best = 0
        # try all single-split points; left best one-transaction, right best one-transaction
        def one(seg):
            lo = float('inf')
            b = 0
            for p in seg:
                if p < lo:
                    lo = p
                elif p - lo > b:
                    b = p - lo
            return b
        for k in range(0, n + 1):
            left = one(prices[:k])
            right = one(prices[k:])
            if left + right > best:
                best = left + right
        return best

